-- Migration 039: Ethical Incidents
-- Persists confirmed ethical incidents generated by the incident_response
-- package (Ethical Architecture Guidelines §11). The table captures severity,
-- kind, affected components, hold status, free-form description, and timestamps.
-- See plan: docs/superpowers/plans/2026-05-07-phase-1c-ethical-architecture-substrate.md Task 11

BEGIN;

CREATE TABLE ethical_incidents (
    id                   UUID        PRIMARY KEY,
    severity             INT         NOT NULL CHECK (severity BETWEEN 1 AND 4),
    kind                 VARCHAR(32) NOT NULL CHECK (kind IN
                             ('clinical_safety', 'trust_violation', 'bias_concern', 'procedural')),
    affected_components  TEXT[]      NOT NULL DEFAULT '{}',
    hold_active          BOOLEAN     NOT NULL DEFAULT FALSE,
    description          TEXT,
    created_at           TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    resolved_at          TIMESTAMPTZ
);

-- Fast lookup of high-severity open incidents (hold_active = true, severity low)
CREATE INDEX idx_ethical_incidents_severity ON ethical_incidents (severity);

-- Query open (unresolved) incidents quickly
CREATE INDEX idx_ethical_incidents_open
    ON ethical_incidents (created_at)
    WHERE resolved_at IS NULL;

COMMIT;
